class Solution:
    def numOfPairs(self, nums, target):
        from collections import Counter
        cnt = Counter(nums)
        total = 0
        for s in nums:
            if target.startswith(s):
                suffix = target[len(s):]
                c = cnt[suffix]
                if suffix == s:
                    c -= 1
                total += c
        return total

