var numOfPairs = function(nums, target) {
    const cnt = new Map();
    for (const s of nums) cnt.set(s, (cnt.get(s) || 0) + 1);
    let total = 0;
    for (const s of nums) {
        if (target.startsWith(s)) {
            const suffix = target.slice(s.length);
            let c = cnt.get(suffix) || 0;
            if (suffix === s) c -= 1;
            total += c;
        }
    }
    return total;
};
